

// =================== STABLE BOOTSTRAP (Local file safe) ===================
(function(){
  const setStatus = (t)=>{ try{ const el=document.getElementById('jsBootStatus'); if(el) el.textContent=t; }catch(e){} };
  const logEl = ()=>document.getElementById('debugLog');
  const sumEl = ()=>document.getElementById('debugSummary');
  const timeEl = ()=>document.getElementById('debugTime');

  window.__DBG__ = {
    logs: [],
    mark: {},
    log: function(msg, obj){
      const ts = new Date().toISOString();
      let line = ts + "  " + msg;
      if (obj !== undefined) {
        try { line += "  " + JSON.stringify(obj).slice(0, 2000); } catch(e) { line += "  [obj stringify failed]"; }
      }
      this.logs.push(line);
      try{ const el=logEl(); if(el) el.textContent=this.logs.slice(-500).join("\n"); }catch(e){}
    },
    stage: function(name){
      this.mark[name]=Date.now();
      this.log("STAGE: "+name);
      try{ const s=sumEl(); if(s) s.textContent="阶段："+Object.keys(this.mark).join(" → "); }catch(e){}
    }
  };

  // mirror console
  ["log","warn","error"].forEach((k)=>{
    const orig=console[k].bind(console);
    console[k]=function(...args){ try{ window.__DBG__.log("console."+k+": "+args.map(a=>String(a)).join(" ")); }catch(e){} orig(...args); };
  });

  // global error hooks
  window.addEventListener("error", (e)=>{
    try{ window.__DBG__.log("WINDOW ERROR: "+(e.message||e)); }catch(_){}
    setStatus("JS状态：发生错误（展开调试面板查看）");
    try{ const el=document.getElementById("errorLog"); if(el) el.textContent="JS错误："+(e.message||e); }catch(_){}
  });
  window.addEventListener("unhandledrejection", (e)=>{
    try{ window.__DBG__.log("UNHANDLED REJECTION: "+String(e.reason)); }catch(_){}
    setStatus("JS状态：发生错误（Promise）");
  });

  try{ const el=timeEl(); if(el) el.textContent="加载时间："+new Date().toLocaleString(); }catch(e){}

  setStatus("JS状态：引导脚本已执行");
  window.__DBG__.stage("bootstrap.loaded");
})();

