function __loadVocabFromB64__(){
  window.__DBG__ && window.__DBG__.stage("vocab.decode.start");
  try {
    const b64 = __VOCAB_B64_PARTS__.join("");
    const jsonStr = decodeURIComponent(escape(atob(b64)));
    SAT_FULL_VOCAB = JSON.parse(jsonStr);
    window.__DBG__ && window.__DBG__.log("vocab.decoded", {len: SAT_FULL_VOCAB.length});
    window.__DBG__ && window.__DBG__.stage("vocab.decode.done");
  } catch (e) {
    console.error("题库解析失败", e);
    const el = document.getElementById('errorLog');
    if (el) el.textContent = "题库解析失败：" + (e && e.message ? e.message : e);
    throw e;
  }
}

// ===== Safe binder =====
function __bind__(id, evt, fn){
  const el = document.getElementById(id);
  if (!el) {
    console.warn("⚠️ 元素未找到，跳过绑定：", id);
    return false;
  }

  // 防止重复绑定（同一个按钮被 onclick + addEventListener 触发两次）
  if (el.dataset && el.dataset.bound === '1') return true;

  const wrapped = function(e){
    // 防抖：同一次点击只执行一次
    if (el.dataset && el.dataset.inflight === '1') return;
    if (el.dataset) el.dataset.inflight = '1';
    try { fn(e); }
    finally {
      // 释放锁（下一个 tick）
      setTimeout(()=>{ if (el.dataset) el.dataset.inflight = '0'; }, 0);
    }
  };

  el.addEventListener(evt, wrapped);
  if (el.dataset) el.dataset.bound = '1';

  // 绑定成功后移除 inline onclick，避免同一次点击执行两次
  if (evt === 'click' && el.getAttribute('onclick')) {
    el.removeAttribute('onclick');
  }
  return true;
}

// ===== Ensure debug panel toggle works =====
function toggleDebugPanel(){
  const panel = document.getElementById('debugPanel');
  if (!panel) return;
  const show = (panel.style.display === 'none' || panel.style.display === '');
  panel.style.display = show ? 'block' : 'none';
}


let batchQuestions = [];

let __EXAM_SUBMITTED__ = false; // 防止重复提交
let errorRecords = [];
let testedWords = new Set();

let SAT_FULL_VOCAB = [];
let __VOCAB_LOADED__ = false;

// --- Vocab loader (GitHub Pages) + cache in IndexedDB/localStorage fallback ---
async function loadVocab(){
  const statusEl = document.getElementById('vocabLoadStatus');
  const setStatus = (t)=>{ if(statusEl) statusEl.textContent = t; };

  const btnIds = ['generateBtn','generate20Btn','generate50Btn','startWrongReviewBtn','startSmartReviewBtn','exportAllVocabBtn','submitAllBtn'];
  btnIds.forEach(id=>{
    const b=document.getElementById(id);
    if(b){ b.disabled = true; b.classList.add('btn-disabled'); }
  });

  const VOCAB_URL = './assets/vocab/sat5000.v1.json';

  try{
    setStatus('正在加载词库…');

    // Try localStorage cache first (fast path)
    try{
      const cached = localStorage.getItem('satVocabCache_v1');
      if(cached){
        const data = JSON.parse(cached);
        if(Array.isArray(data) && data.length){
          SAT_FULL_VOCAB = data;
          __VOCAB_LOADED__ = true;
          setStatus('词库加载完成（缓存）：' + SAT_FULL_VOCAB.length + ' 词');
          btnIds.forEach(id=>{
            const b=document.getElementById(id);
            if(b){ b.disabled = false; b.classList.remove('btn-disabled'); }
          });
          try{ if(typeof updateStats === 'function') updateStats(); } catch(_){}
          // Continue to refresh in background (no await)
          fetch(VOCAB_URL, {cache:'force-cache'}).then(r=>r.ok?r.json():null).then(fresh=>{
            if(Array.isArray(fresh) && fresh.length){
              // case-insensitive dedupe
              const map=new Map();
              fresh.forEach(v=>{
                const w=String(v.word||'').trim(); if(!w) return;
                const k=w.toLowerCase();
                if(!map.has(k)) map.set(k, v);
              });
              const deduped=Array.from(map.values());
              SAT_FULL_VOCAB = deduped;
              localStorage.setItem('satVocabCache_v1', JSON.stringify(deduped));
              try{ if(typeof updateStats === 'function') updateStats(); } catch(_){}
              setStatus('词库加载完成：' + SAT_FULL_VOCAB.length + ' 词');
            }
          }).catch(()=>{});
          return;
        }
      }
    }catch(_){}

    const res = await fetch(VOCAB_URL, {cache:'force-cache'});
    if(!res.ok) throw new Error('HTTP ' + res.status);

    const data = await res.json();
    if(!Array.isArray(data)) throw new Error('词库格式不是数组');

    // case-insensitive dedupe (aviary/Aviary)
    const map=new Map();
    data.forEach(v=>{
      const w=String(v.word||'').trim(); if(!w) return;
      const k=w.toLowerCase();
      if(!map.has(k)) map.set(k, v);
    });
    const deduped=Array.from(map.values());

    SAT_FULL_VOCAB = deduped;
    __VOCAB_LOADED__ = true;

    try{ localStorage.setItem('satVocabCache_v1', JSON.stringify(deduped)); }catch(_){}

    setStatus('词库加载完成：' + SAT_FULL_VOCAB.length + ' 词');

    btnIds.forEach(id=>{
      const b=document.getElementById(id);
      if(b){ b.disabled = false; b.classList.remove('btn-disabled'); }
    });

    try{ if(typeof updateStats === 'function') updateStats(); } catch(_){}
  }catch(e){
    console.error('loadVocab failed', e);
    setStatus('词库加载失败：' + (e && e.message ? e.message : e));
    alert('词库加载失败：请确认通过 GitHub Pages 地址打开（不要本地双击），并检查 assets/vocab/sat5000.v1.json 是否存在。');
  }
}

const TODAY = new Date().toLocaleDateString('zh-CN');

async function loadVocab() {
  // 题库已内匌在本 HTML 中（无需 fetch）
  try {
    document.getElementById('networkStatus').textContent = "✅ 5000词题库已加载（内嵌模式，无需网络）";
    document.getElementById('errorLog').textContent = "无错误（内嵌模式）";
    startNormalMode();
    updateStats();
  } catch (error) {
    console.error("❌ 初始化失败", error);
    document.getElementById('networkStatus').textContent = "❌ 初始化失败，请检查控制台";
    document.getElementById('errorLog').textContent = String(error);
  }
}

function initLocalStorage() {
  // 已考词汇（case-insensitive：统一存小写）
  if (!localStorage.getItem('satTestedWords')) {
    localStorage.setItem('satTestedWords', JSON.stringify([]));
  }
  try {
    const saved = JSON.parse(localStorage.getItem('satTestedWords') || '[]');
    testedWords = new Set((Array.isArray(saved) ? saved : []).map(w => String(w||'').toLowerCase()).filter(Boolean));
    // 纠正存储格式
    localStorage.setItem('satTestedWords', JSON.stringify(Array.from(testedWords)));
  } catch(e) {
    testedWords = new Set();
    localStorage.setItem('satTestedWords', JSON.stringify([]));
  }

  // 错题本
  if (!localStorage.getItem('satErrorRecords')) {
    localStorage.setItem('satErrorRecords', JSON.stringify([]));
  }
  try {
    errorRecords = JSON.parse(localStorage.getItem('satErrorRecords') || '[]');
    if (!Array.isArray(errorRecords)) errorRecords = [];
  } catch(e) {
    errorRecords = [];
    localStorage.setItem('satErrorRecords', JSON.stringify([]));
  }
}

function updateStats() {
  const total = Array.isArray(SAT_FULL_VOCAB) ? SAT_FULL_VOCAB.length : 0;
  const tested = (typeof testedWords !== 'undefined' && testedWords && testedWords.size) ? testedWords.size : 0;
  const error = (typeof errorRecords !== 'undefined' && Array.isArray(errorRecords)) ? (new Set(errorRecords.map(x => String(x.word||'').toLowerCase()))).size : 0;
  const todayError = (typeof errorRecords !== 'undefined' && Array.isArray(errorRecords)) ? errorRecords.filter(item => item.date === TODAY).length : 0;
  const remaining = Math.max(0, total - tested);

  const setText = (id, value) => {
    const el = document.getElementById(id);
    if (el) el.textContent = value;
  };

  setText('totalVocabCount', total);
  setText('testedVocabCount', tested);
  setText('errorVocabCount', error);
  setText('remainingVocabCount', remaining);

  const todayEl = document.getElementById('todayErrorCount');
  if (todayEl) todayEl.textContent = `今日错题：${todayError}`;

  const testedCountEl = document.getElementById('testedWordCount');
  if (testedCountEl) testedCountEl.textContent = `总单词数：${tested}`;

  window.__DBG__ && window.__DBG__.log("updateStats", { total, tested, error, remaining });
}

function generateQuestions(count = 10){
  __EXAM_SUBMITTED__ = false;
  const submitBtn = document.getElementById('submitAllBtn');
  if (submitBtn) { submitBtn.disabled = false; submitBtn.classList.remove('btn-disabled'); submitBtn.textContent = '提交答案'; }

  if (SAT_FULL_VOCAB.length === 0) {
    alert("词汇库未加载");
    return;
  }
  document.getElementById('loadingOverlay').style.display = 'flex';
  const selectedDifficulty = document.getElementById('selectedDifficulty').value;
  let filteredWords = SAT_FULL_VOCAB.filter(item => !testedWords.has(String(item.word||'').toLowerCase()));
  if (selectedDifficulty !== "All") {
    filteredWords = filteredWords.filter(item => item.difficulty === selectedDifficulty);
  }
  let selectedWords = [];
  if (filteredWords.length < count) {
    selectedWords = [...filteredWords];
    const testedArray = SAT_FULL_VOCAB.filter(item => testedWords.has(String(item.word||'').toLowerCase()));
    const testedFiltered = selectedDifficulty !== "All" 
      ? testedArray.filter(item => item.difficulty === selectedDifficulty)
      : testedArray;
    const randomTested = testedFiltered.sort(() => 0.5 - Math.random()).slice(0, count - filteredWords.length);
    selectedWords = [...selectedWords, ...randomTested];
  } else {
    selectedWords = filteredWords.sort(() => 0.5 - Math.random()).slice(0, count);
  }
  batchQuestions = selectedWords.map((item, index) => {
    const options = [...item.distractors, item.word];
    const shuffledOptions = options.sort(() => 0.5 - Math.random());
    return {
      id: index,
      word: item.word,
      definition: item.definition,
      sentence: item.sentence,
      options: shuffledOptions,
      correctAnswer: item.word,
      userAnswer: '',
      difficulty: item.difficulty
    };
  });
  renderQuestions();
  document.getElementById('loadingOverlay').style.display = 'none';
  updateStats();
}

function renderQuestions() {
  const container = document.getElementById('questionsContainer');
  container.innerHTML = '';
  batchQuestions.forEach(question => {
    const difficultyTag = {
      "Basic": "<span style='background:#0ea5e9;color:white;padding:2px 6px;border-radius:3px;font-size:12px;margin-left:8px;'>基础</span>",
      "Medium": "<span style='background:#8b5cf6;color:white;padding:2px 6px;border-radius:3px;font-size:12px;margin-left:8px;'>进阶</span>",
      "Hard": "<span style='background:#dc2626;color:white;padding:2px 6px;border-radius:3px;font-size:12px;margin-left:8px;'>冲刺</span>"
    }[question.difficulty];
    const questionDiv = document.createElement('div');
    questionDiv.className = 'question-item';
    questionDiv.id = `question_${question.id}`;
    questionDiv.innerHTML = `
      <div class="question-text"><strong>Q${question.id + 1}:</strong> ${question.sentence} ${difficultyTag}</div>
      ${question.options.map((option, optIndex) => `
        <div class="option">
          <input type="radio" name="q${question.id}" id="q${question.id}_opt${optIndex}" value="${option}">
          <label for="q${question.id}_opt${optIndex}">${option}</label>
        </div>
      `).join('')}
      <div class=\"question-feedback\" id=\"q${question.id}_feedback\" style=\"display:none;margin-top:10px;padding:10px;border-radius:8px;background:rgba(0,0,0,0.04);\"></div>
    `;
    container.appendChild(questionDiv);
  });
  document.getElementById('submitAllBtn').style.display = 'block';
  document.getElementById('submitAllBtn').disabled = false;
}


function submitAnswers() {
  const submitBtn = document.getElementById('submitAllBtn');

  // 已提交则不允许重复提交
  if (__EXAM_SUBMITTED__) {
    alert('本轮题目已提交。请先生成新题目再提交。');
    return;
  }

  // 1) 必须全部作答，否则不允许提交
  const unanswered = [];
  let firstUnansweredId = null;

  batchQuestions.forEach(q => {
    const selected = document.querySelector(`input[name="q${q.id}"]:checked`);
    if (!selected) {
      unanswered.push(q.id + 1);
      if (firstUnansweredId === null) firstUnansweredId = q.id;
    }
  });

  if (unanswered.length > 0) {
    // 高亮未作答题
    batchQuestions.forEach(q => {
      const selected = document.querySelector(`input[name="q${q.id}"]:checked`);
      const block = document.getElementById(`question_${q.id}`);
      if (!selected && block) block.classList.add('question-unanswered');
    });

    alert(`还有 ${unanswered.length} 题未作答（题号： ${unanswered.join(', ')} ）。请先完成再提交。`);

    // 自动滚动到第一道未作答题
    const target = document.getElementById(`question_${firstUnansweredId}`);
    if (target) target.scrollIntoView({behavior:'smooth', block:'center'});
    return;
  }

  // ===== 全部作答后才会进入这里 =====
  let correctCount = 0;
  let wrongCount = 0;
  const wrongQuestions = [];

  batchQuestions.forEach(question => {
    const selectedOption = document.querySelector(`input[name="q${question.id}"]:checked`);
    question.userAnswer = selectedOption ? selectedOption.value : null;

    const isCorrect = question.userAnswer === question.correctAnswer;
    if (isCorrect) correctCount++;
    else {
      wrongCount++;
      wrongQuestions.push(question);
    }
  });

  // ===== 1) 提交后才计入“已考词汇” =====
  try {
    if (typeof testedWords === 'undefined' || !testedWords) window.testedWords = new Set();
    batchQuestions.forEach(q => { if (q && q.word) testedWords.add(String(q.word).toLowerCase()); });
    localStorage.setItem('satTestedWords', JSON.stringify(Array.from(testedWords)));
  } catch(e) { console.warn('保存已考词汇失败', e); }

  // ===== 2) 记录错题到错题本（satErrorRecords）=====
  try {
    if (typeof errorRecords === 'undefined' || !Array.isArray(errorRecords)) window.errorRecords = [];
    const today = (typeof TODAY !== 'undefined' ? TODAY : new Date().toISOString().slice(0,10));

    wrongQuestions.forEach(q => {
      if (!q || !q.word) return;
      errorRecords.push({
        word: q.word,
        definition: q.definition || '',
        sentence: q.sentence || '',
        difficulty: q.difficulty || '',
        correctAnswer: q.correctAnswer,
        userAnswer: q.userAnswer,
        date: today
      });
    });

    localStorage.setItem('satErrorRecords', JSON.stringify(errorRecords));
  } catch(e) { console.warn('保存错题本失败', e); }

  // ===== 标记为已提交 + 禁用按钮 =====
  __EXAM_SUBMITTED__ = true;
  if (submitBtn) {
    submitBtn.disabled = true;
    submitBtn.classList.add('btn-disabled');
    submitBtn.textContent = '已提交';
  }

  // 更新统计
  try { updateStats(); } catch(_) {}

  alert(`提交完成：\n正确 ${correctCount} 题，错误 ${wrongCount} 题`);
}
function showTestedWords() {
  try {
    const container = document.getElementById('testedWordsContainer');
    const list = document.getElementById('testedWordsList');
    if (!container || !list) {
      alert('页面缺少已考单词容器（testedWordsContainer/testedWordsList）。');
      return;
    }

    // 容错：确保 testedWords 存在且为 Set
    if (typeof testedWords === 'undefined' || !testedWords) {
      window.testedWords = new Set();
    } else if (!(testedWords instanceof Set)) {
      try { window.testedWords = new Set(Array.isArray(testedWords) ? testedWords : Array.from(testedWords)); } catch (_) { window.testedWords = new Set(); }
    }

    const isHidden = (container.style.display === 'none' || container.style.display === '');
    if (isHidden) {
      container.style.display = 'block';
      try { container.scrollIntoView({behavior:'smooth', block:'start'}); } catch(_) {}
      const testedArray = Array.from(testedWords);
      if (!Array.isArray(SAT_FULL_VOCAB)) {
        list.innerHTML = '<p>题库未加载，请刷新页面再试。</p>';
      } else if (testedArray.length === 0) {
        list.innerHTML = '<p>暂无已考单词</p>';
      } else {
        list.innerHTML = testedArray.map(word => {
          const vocabItem = SAT_FULL_VOCAB.find(item => item.word === word);
          const difficultyTag = vocabItem ? {
            "Basic": "<span style='background:#0ea5e9;color:white;padding:2px 6px;border-radius:3px;font-size:12px;margin-left:8px;'>基础</span>",
            "Medium": "<span style='background:#8b5cf6;color:white;padding:2px 6px;border-radius:3px;font-size:12px;margin-left:8px;'>进阶</span>",
            "Hard": "<span style='background:#dc2626;color:white;padding:2px 6px;border-radius:3px;font-size:12px;margin-left:8px;'>冲刺</span>"
          }[vocabItem.difficulty] : '';
          const defText = vocabItem ? vocabItem.definition : '暂无释义';
          return `<div class="word-item"><div><strong>${word}</strong> ${difficultyTag} - ${defText}</div></div>`;
        }).join('');
      }

      // 自动定位到已考单词区域，避免用户以为“没反应”
      container.scrollIntoView({ behavior: 'smooth', block: 'start' });
    } else {
      container.style.display = 'none';
    }
  } catch (e) {
    console.error(e);
    alert('查看已考单词失败：' + (e && e.message ? e.message : e));
  }
}

function showErrorBook() {
  const container = document.getElementById('errorBookContainer');
  const list = document.getElementById('todayErrorList'); // 复用现有容器
  if (!container || !list) {
    alert('页面缺少错题本容器（errorBookContainer/todayErrorList）。');
    return;
  }

  const isHidden = (container.style.display === 'none' || container.style.display === '');
  if (isHidden) {
    container.style.display = 'block';
    try { container.scrollIntoView({behavior:'smooth', block:'start'}); } catch(_) {}

    // 展示“全部错题”（按单词聚合，显示次数与最近一次日期）
    const allErrors = Array.isArray(errorRecords) ? errorRecords.slice() : [];
    if (allErrors.length === 0) {
      list.innerHTML = '<p>暂无错题</p>';
      return;
    }

    const byWord = new Map();
    allErrors.forEach(e => {
      if (!e || !e.word) return;
      const key = e.word;
      const cur = byWord.get(key) || { word:key, count:0, last:null, sample:e };
      cur.count += 1;
      // 记录最近一次
      if (!cur.last || (e.date && String(e.date) > String(cur.last.date || ''))) cur.last = e;
      // 保留一个样本用于展示释义/例句/难度
      if (!cur.sample && e.definition) cur.sample = e;
      byWord.set(key, cur);
    });

    const rows = Array.from(byWord.values()).sort((a,b)=>{
      const da = (a.last && a.last.date) ? String(a.last.date) : '';
      const db = (b.last && b.last.date) ? String(b.last.date) : '';
      if (da !== db) return db.localeCompare(da);
      return a.word.localeCompare(b.word);
    });

    list.innerHTML = rows.map(item => {
      const e = item.last || item.sample || {};
      const difficultyTag = {
        "Basic": "<span style='background:#0ea5e9;color:white;padding:2px 6px;border-radius:3px;font-size:12px;'>基础</span>",
        "Medium": "<span style='background:#8b5cf6;color:white;padding:2px 6px;border-radius:3px;font-size:12px;'>进阶</span>",
        "Hard": "<span style='background:#dc2626;color:white;padding:2px 6px;border-radius:3px;font-size:12px;'>冲刺</span>"
      }[e.difficulty] || "";

      const lastDate = e.date ? `<span style="color:#64748b;font-size:12px;">（最近：${e.date}）</span>` : "";
      const def = e.definition ? ` - ${e.definition}` : "";
      const sent = e.sentence ? `<p style="margin:5px 0;font-size:12px;">${e.sentence}</p>` : "";
      const ua = e.userAnswer ? `<span class="wrong-answer">${e.userAnswer}</span>` : "";
      const ca = e.correctAnswer ? `<span class="correct-answer">${e.correctAnswer}</span>` : "";

      const qaLine = (ua || ca) ? `<p style="font-size:12px;margin:0;">你的答案：${ua} | 正确答案：${ca}</p>` : "";

      return `
        <div class="word-item">
          <div style="flex:1;">
            <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
              <strong>${item.word}</strong>
              ${difficultyTag}
              <span style="background:#e2e8f0;color:#0f172a;padding:2px 8px;border-radius:999px;font-size:12px;">错题次数：${item.count}</span>
              ${lastDate}
            </div>
            <div style="margin-top:4px;">${def}</div>
            ${sent}
            ${qaLine}
          </div>
        </div>
      `;
    }).join('');

  } else {
    container.style.display = 'none';
  }
}

function exportTestedWords() {
  const testedArray = Array.from(testedWords);
  if (testedArray.length === 0) {
    alert('暂无已考单词可导出');
    return;
  }
  let csvContent = "单词,难度,释义,例句\n";
  testedArray.forEach(word => {
    const vocabItem = SAT_FULL_VOCAB.find(item => item.word === word);
    if (vocabItem) {
      const sentence = vocabItem.sentence.replace(/"/g, '""');
      const definition = vocabItem.definition.replace(/"/g, '""');
      csvContent += `"${word}","${vocabItem.difficulty}","${definition}","${sentence}"\n`;
    }
  });
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", `SAT已考单词_${new Date().toLocaleDateString()}.csv`);
  link.style.display = "none";
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
}

