/* =========================
   Pro Mode: Adaptive Learning
   ========================= */

// 本地学习数据：每个单词的正确/错误、掌握度、下次复习时间（简化间隔复习）
let vocabStats = JSON.parse(localStorage.getItem("sat_vocab_stats") || "{}");
// 题目模式：normal | wrong | smart
let currentMode = "normal";

function saveVocabStats() {
  localStorage.setItem("sat_vocab_stats", JSON.stringify(vocabStats));
}

function getWordStat(word) {
  if (!vocabStats[word]) {
    vocabStats[word] = { correct: 0, wrong: 0, score: 0, streak: 0, nextReviewAt: 0, lastSeenAt: 0 };
  }
  return vocabStats[word];
}

// 简化掌握度：正确率 + 连对加成；并给出下次复习时间（类似Anki的简化间隔）
function updateWordStats(word, isCorrect) {
  const s = getWordStat(word);
  s.lastSeenAt = Date.now();

  if (isCorrect) {
    s.correct += 1;
    s.streak = (s.streak || 0) + 1;
  } else {
    s.wrong += 1;
    s.streak = 0;
  }

  const total = s.correct + s.wrong;
  const base = total ? (s.correct / total) : 0;
  const streakBonus = Math.min(0.15, (s.streak || 0) * 0.03);
  s.score = Math.max(0, Math.min(1, base + streakBonus));

  // 安排下次复习：错题尽快、熟练的间隔更长（分钟→小时→天）
  let minutes;
  if (!isCorrect) minutes = 5;                       // 做错：5分钟后再来
  else if (s.score < 0.5) minutes = 30;
  else if (s.score < 0.7) minutes = 6 * 60;         // 6小时
  else if (s.score < 0.85) minutes = 24 * 60;       // 1天
  else minutes = 3 * 24 * 60;                        // 3天

  s.nextReviewAt = Date.now() + minutes * 60 * 1000;
  saveVocabStats();
}

function resetLearningData() {
  const msg = `确定要重置学习数据吗？

将清空：
• 已考单词（tested）
• 错题本（error book）
• 单词掌握度/间隔复习数据（vocab stats）

题库不会删除。`;

  if (!confirm(msg)) return;

  try {
    // 1) 清空内存数据
    try { testedWords = new Set(); } catch (e) { window.testedWords = new Set(); }
    try { errorRecords = []; } catch (e) { window.errorRecords = []; }
    try { vocabStats = {}; } catch (e) { window.vocabStats = {}; }

    // 2) 清空本地存储（与本项目一致的 key）
    localStorage.setItem('satTestedWords', JSON.stringify([]));
    localStorage.setItem('satErrorRecords', JSON.stringify([]));
    localStorage.setItem('sat_vocab_stats', JSON.stringify({}));

    // 3) 关闭/清空相关面板内容（避免用户以为没变化）
    const testedContainer = document.getElementById('testedWordsContainer');
    const testedList = document.getElementById('testedWordsList');
    if (testedContainer) testedContainer.style.display = 'none';
    if (testedList) testedList.innerHTML = '';

    const errorContainer = document.getElementById('errorBookContainer');
    const errorList = document.getElementById('errorBookList');
    if (errorContainer) errorContainer.style.display = 'none';
    if (errorList) errorList.innerHTML = '';

    // 4) 刷新统计与学习面板
    if (typeof updateStats === 'function') updateStats();
    if (typeof renderLearningStats === 'function') renderLearningStats();
    if (typeof renderProgressBar === 'function') renderProgressBar();

    alert("✅ 已重置学习数据（如仍看到旧内容，请刷新页面）。");
  } catch (e) {
    console.error(e);
    alert("❌ 重置失败：" + (e && e.message ? e.message : e));
  }
}

function setModeBadge(modeText) {
  const badge = document.getElementById("modeBadge");
  if (!badge) return;
  badge.textContent = "模式：" + modeText;
}

// 生成“智能池”：到期复习优先，其次掌握度低，再其次久未见
function getSmartPool() {
  const now = Date.now();
  return SAT_FULL_VOCAB.slice().sort((a, b) => {
    const sa = getWordStat(a.word);
    const sb = getWordStat(b.word);

    const aDue = (sa.nextReviewAt || 0) <= now ? 0 : 1;
    const bDue = (sb.nextReviewAt || 0) <= now ? 0 : 1;
    if (aDue !== bDue) return aDue - bDue;

    const aScore = sa.score ?? 0;
    const bScore = sb.score ?? 0;
    if (aScore !== bScore) return aScore - bScore;

    const aSeen = sa.lastSeenAt || 0;
    const bSeen = sb.lastSeenAt || 0;
    return aSeen - bSeen;
  });
}

// 错题池：来自 errorRecords（错题本）
function getWrongPool() {
  const wrongSet = new Set((errorRecords || []).map(e => String(e.word).toLowerCase()));
  return SAT_FULL_VOCAB.filter(x => wrongSet.has(String(x.word).toLowerCase()));
}

/* ========== UI: Progress & Nav ========== */

function renderProgressBar() {
  const container = document.getElementById("progressBarContainer");
  if (!container) return;

  const answered = document.querySelectorAll('input[type="radio"]:checked').length;
  const total = batchQuestions.length || 0;
  const percent = total ? Math.round((answered / total) * 100) : 0;

  container.innerHTML = `
    <div style="background:#e5e7eb;height:10px;border-radius:999px;overflow:hidden;">
      <div style="width:${percent}%;height:10px;background:#2563eb;transition:width 0.25s;"></div>
    </div>
    <div style="margin-top:6px;font-size:13px;color:#475569;">进度：${answered} / ${total}（${percent}%）</div>
  `;
}

function renderQuestionNav() {
  const nav = document.getElementById("questionNav");
  if (!nav) return;

  nav.innerHTML = "";
  batchQuestions.forEach((q, index) => {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "nav-btn unanswered";
    btn.textContent = index + 1;
    btn.title = "跳转到第 " + (index + 1) + " 题";

    btn.addEventListener("click", () => {
      const target = document.getElementById(`question_${q.id}`);
      if (target) target.scrollIntoView({ behavior: "smooth", block: "center" });
      highlightCurrentNav(index);
    });

    nav.appendChild(btn);
  });

  updateQuestionStatus();
}

function highlightCurrentNav(activeIndex) {
  const buttons = document.querySelectorAll("#questionNav .nav-btn");
  buttons.forEach((b, i) => b.classList.toggle("current", i === activeIndex));
}

function updateQuestionStatus() {
  const buttons = document.querySelectorAll("#questionNav .nav-btn");
  batchQuestions.forEach((q, index) => {
    const btn = buttons[index];
    if (!btn) return;

    const answered = document.querySelector(`input[name="q${q.id}"]:checked`);
    btn.classList.remove("unanswered", "answered", "wrong", "correct");
    if (answered) btn.classList.add("answered");
    else btn.classList.add("unanswered");
  });
}

document.addEventListener("change", (e) => {
  if (e.target && e.target.type === "radio") {
    renderProgressBar();
    updateQuestionStatus();

    const name = e.target.name;
    const m = name.match(/^q(\d+)$/);
    if (m) {
      const id = Number(m[1]);
      const block = document.getElementById(`question_${id}`);
      if (block) block.classList.remove("question-unanswered");
    }
  }
});

/* ========== Learning Stats Panel ========== */

function renderLearningStats() {
  const el = document.getElementById("learningStats");
  if (!el) return;

  const entries = Object.entries(vocabStats);
  if (entries.length === 0) {
    el.innerHTML = `
      <div style="padding:12px;border-radius:12px;background:white;border:1px solid rgba(0,0,0,0.06);">
        <b>学习统计</b>
        <div style="margin-top:6px;color:#64748b;font-size:13px;">暂无学习数据。做几轮题后这里会显示掌握度与复习建议。</div>
      </div>
    `;
    return;
  }

  const stats = entries.map(([w, s]) => s);
  const avg = stats.reduce((a, s) => a + (s.score || 0), 0) / stats.length;
  const mastered = stats.filter(s => (s.score || 0) >= 0.85 && (s.correct + s.wrong) >= 3).length;
  const struggling = stats.filter(s => (s.score || 0) < 0.5 && (s.correct + s.wrong) >= 2).length;

  const now = Date.now();
  const dueCount = stats.filter(s => (s.nextReviewAt || 0) <= now && (s.correct + s.wrong) > 0).length;

  el.innerHTML = `
    <div style="padding:12px;border-radius:12px;background:white;border:1px solid rgba(0,0,0,0.06);">
      <div style="display:flex;align-items:center;justify-content:space-between;gap:10px;flex-wrap:wrap;">
        <b>学习统计</b>
        <span style="font-size:12px;color:#64748b;">基于本机浏览器 localStorage</span>
      </div>
      <div style="margin-top:10px;display:flex;gap:12px;flex-wrap:wrap;">
        <div style="min-width:180px;">
          <div style="font-size:13px;color:#64748b;">已学习词汇</div>
          <div style="font-size:20px;font-weight:800;">${stats.length}</div>
        </div>
        <div style="min-width:180px;">
          <div style="font-size:13px;color:#64748b;">平均掌握度</div>
          <div style="font-size:20px;font-weight:800;">${(avg * 100).toFixed(1)}%</div>
        </div>
        <div style="min-width:180px;">
          <div style="font-size:13px;color:#64748b;">已掌握（≥85%）</div>
          <div style="font-size:20px;font-weight:800;">${mastered}</div>
        </div>
        <div style="min-width:180px;">
          <div style="font-size:13px;color:#64748b;">薄弱（<50%）</div>
          <div style="font-size:20px;font-weight:800;">${struggling}</div>
        </div>
        <div style="min-width:180px;">
          <div style="font-size:13px;color:#64748b;">到期应复习</div>
          <div style="font-size:20px;font-weight:800;">${dueCount}</div>
        </div>
      </div>
      <div style="margin-top:10px;color:#475569;font-size:13px;line-height:1.6;">
        提示：点击 <b>智能复习（错题优先）</b> 会优先抽取“到期复习 + 掌握度低”的单词。
      </div>
    </div>
  `;
}

/* ========== Mode Buttons ========== */

function startNormalMode() { currentMode = "normal"; setModeBadge("普通"); }
function startWrongMode() { currentMode = "wrong"; setModeBadge("错题强化"); }
function startSmartMode() { currentMode = "smart"; setModeBadge("智能复习"); }

function attachProModeHandlers() {
  const wrongBtn = document.getElementById("reviewWrongBtn");
  const smartBtn = document.getElementById("reviewSmartBtn");
  const resetBtn = document.getElementById("resetLearningBtn");

  if (wrongBtn) wrongBtn.addEventListener("click", () => { startWrongMode(); generateNewSet(true); });
  if (smartBtn) smartBtn.addEventListener("click", () => { startSmartMode(); generateNewSet(true); });
  if (resetBtn) resetBtn.addEventListener("click", () => resetLearningData());
}

/* ========== Generate Questions Override ========== */

function pickFromPool(pool, n) {
  const picked = [];
  const used = new Set();
  for (const item of pool) {
    const key = String(item.word).toLowerCase();
    if (used.has(key)) continue;
    used.add(key);
    picked.push(item);
    if (picked.length >= n) break;
  }
  if (picked.length < n) {
    for (const item of SAT_FULL_VOCAB) {
      const key = String(item.word).toLowerCase();
      if (used.has(key)) continue;
      used.add(key);
      picked.push(item);
      if (picked.length >= n) break;
    }
  }
  return picked;
}

function buildQuestionsFromItems(items, count) {
  const questions = [];
  const total = Math.min(count, items.length);
  for (let i = 0; i < total; i++) {
    const item = items[i];
    const correct = item.word;

    const opts = [correct, ...(item.distractors || [])].slice(0, 4);
    while (opts.length < 4) opts.push(SAT_FULL_VOCAB[Math.floor(Math.random() * SAT_FULL_VOCAB.length)].word);

    for (let j = opts.length - 1; j > 0; j--) {
      const k = Math.floor(Math.random() * (j + 1));
      [opts[j], opts[k]] = [opts[k], opts[j]];
    }

    questions.push({
      id: i,
      word: item.word,
      definition: item.definition,
      sentence: item.sentence,
      correctAnswer: correct,
      options: opts,
      difficulty: item.difficulty || "Medium"
    });
  }
  return questions;
}

function generateNewSet(forceRerender = false) {
  const countInput = document.getElementById("questionCount");
  const n = countInput ? Math.max(1, Math.min(50, parseInt(countInput.value || "10", 10))) : 10;

  let pool;
  if (currentMode === "wrong") {
    pool = getWrongPool();
    if (!pool || pool.length === 0) {
      alert("错题本为空：先做几轮题，产生错题后再用“错题强化模式”。将改为普通模式出题。");
      startNormalMode();
      pool = SAT_FULL_VOCAB.slice();
    }
  } else if (currentMode === "smart") {
    pool = getSmartPool();
  } else {
    pool = SAT_FULL_VOCAB.slice();
    pool.sort((a, b) => (getWordStat(a.word).score ?? 0) - (getWordStat(b.word).score ?? 0));
  }

  const topK = Math.min(Math.max(n * 10, 80), pool.length);
  const head = pool.slice(0, topK);
  head.sort(() => Math.random() - 0.5);

  const pickedItems = pickFromPool(head, n);
  batchQuestions = buildQuestionsFromItems(pickedItems, n);

  renderQuestions();
  renderProgressBar();
  renderQuestionNav();
  renderLearningStats();

  const resultArea = document.getElementById('totalResultArea');
  if (resultArea) resultArea.style.display = 'none';
  const submitBtn = document.getElementById('submitAllBtn');
  if (submitBtn) submitBtn.disabled = false;
}

function attachGenerateHook() {
  const btn = document.getElementById("generateBtn");
  if (!btn) return;
  btn.addEventListener("click", () => { generateNewSet(true); });
}



// ===== Clear buttons (independent reset) =====
function clearTestedWords() {
  const msg = `确定清空【已考词汇】吗？

将清空：
• 已考单词列表
• 与已考相关的统计（已考数量/剩余数量）

不会清空错题本，也不会清空学习掌握度数据。`;
  if (!confirm(msg)) return;

  try {
    // memory
    try { testedWords = new Set(); } catch (e) { window.testedWords = new Set(); }
    // storage
    localStorage.setItem('satTestedWords', JSON.stringify([]));

    // UI
    const container = document.getElementById('testedWordsContainer');
    const list = document.getElementById('testedWordsList');
    if (list) list.innerHTML = '<p>暂无已考单词</p>';
    if (container) container.style.display = 'none';

    if (typeof updateStats === 'function') updateStats();
    if (typeof renderLearningStats === 'function') renderLearningStats();
    if (typeof renderProgressBar === 'function') renderProgressBar();

    alert('✅ 已清空已考词汇');
  } catch (e) {
    console.error(e);
    alert('❌ 清空失败：' + (e && e.message ? e.message : e));
  }
}

