// ===== Debug Self-Check =====
function __selfCheck__() {
  window.__DBG__ && window.__DBG__.stage("selfcheck.start");
  const ids = [
    'toggleDebugBtn','generateBtn','generate20Btn','generate50Btn','submitAllBtn',
    'showTestedWordsBtn','showErrorBookBtn','clearErrorBtn','debugPanel'
  ];
  const found = {};
  ids.forEach(id => found[id] = !!document.getElementById(id));

  let vocabLen = null;
  try { vocabLen = Array.isArray(SAT_FULL_VOCAB) ? SAT_FULL_VOCAB.length : null; } catch(e){ vocabLen = 'ERR:'+e.message; }

  const summary = {
    userAgent: navigator.userAgent,
    protocol: location.protocol,
    href: location.href.slice(0,160),
    elementsFound: found,
    vocabLen: vocabLen,
    hasFunctions: {
      generateQuestions: typeof generateQuestions === 'function',
      submitAnswers: typeof submitAnswers === 'function',
      toggleDebugPanel: typeof toggleDebugPanel === 'function',
      loadVocab: typeof loadVocab === 'function',
      updateStats: typeof updateStats === 'function'
    }
  };

  window.__DBG__ && window.__DBG__.log("SELF CHECK RESULT", summary);

  const s = document.getElementById('debugSummary');
  if (s) {
    s.textContent =
      `自检：protocol=${summary.protocol} | vocabLen=${summary.vocabLen} | ` +
      `generateQuestions=${summary.hasFunctions.generateQuestions} | submitAnswers=${summary.hasFunctions.submitAnswers} | ` +
      `toggleDebugPanel=${summary.hasFunctions.toggleDebugPanel}`;
  }
  return summary;
}

(function attachDebugButtons(){
  const runBtn = document.getElementById('runSelfCheckBtn');
  if (runBtn) runBtn.onclick = () => { try{ __selfCheck__(); alert('自检已完成：展开“详细日志”并复制发我即可。'); }catch(e){ alert('自检失败：'+e.message); } };

  const copyBtn = document.getElementById('copyDebugBtn');
  if (copyBtn) copyBtn.onclick = async () => {
    const info = {
      time: new Date().toISOString(),
      href: location.href,
      protocol: location.protocol,
      vocabLen: (Array.isArray(window.SAT_FULL_VOCAB) ? window.SAT_FULL_VOCAB.length : null),
      logs: (window.__DBG__ && window.__DBG__.logs) ? window.__DBG__.logs.slice(-250) : []
    };
    const text = JSON.stringify(info, null, 2);
    try{
      await navigator.clipboard.writeText(text);
      alert('调试信息已复制到剪贴板，直接粘贴发我即可。');
    }catch(e){
      prompt('复制下面内容发我：', text);
    }
  };
})();


