if (typeof exportTestedWordsToCSV !== 'function') {
  function exportTestedWordsToCSV() {
    try {
      if (typeof testedWords === 'undefined' || !testedWords || testedWords.size === 0) {
        alert('暂无可导出的已考单词。');
        return;
      }
      const arr = Array.from(testedWords);
      const header = "word\n";
      const csv = header + arr.map(w => `"${String(w).replace(/"/g, '""')}"`).join("\n");

      const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = "tested_words.csv";
      document.body.appendChild(a);
      a.click();
      a.remove();
      URL.revokeObjectURL(url);
    } catch (e) {
      console.error(e);
      alert('导出失败：' + (e && e.message ? e.message : e));
    }
  }
}


// =========================
// 复习模式实现（错题强化 / 智能复习）
// =========================
function __pickRandom__(arr, n){
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a.slice(0, Math.max(0, n));
}

function __setExamReady__(){
  __EXAM_SUBMITTED__ = false;
  const submitBtn = document.getElementById('submitAllBtn');
  if (submitBtn) {
    submitBtn.disabled = false;
    submitBtn.classList.remove('btn-disabled');
    submitBtn.textContent = '提交答案';
    submitBtn.style.display = 'block';
  }
}

function __buildBatchFromVocab__(words){
  batchQuestions = words.map((item, index) => {
    const distractors = Array.isArray(item.distractors) ? item.distractors.slice() : [];
    const options = [...distractors, item.word];
    const shuffledOptions = options.sort(() => 0.5 - Math.random());
    return {
      id: index,
      word: item.word,
      definition: item.definition,
      sentence: item.sentence,
      options: shuffledOptions,
      correctAnswer: item.word,
      userAnswer: '',
      difficulty: item.difficulty
    };
  });
  __setExamReady__();
  renderQuestions();
}

function startWrongReviewMode(count = 10){
  if (!Array.isArray(SAT_FULL_VOCAB) || SAT_FULL_VOCAB.length === 0) {
    alert("词汇库未加载");
    return;
  }
  const errs = Array.isArray(errorRecords) ? errorRecords : [];
  if (errs.length === 0) {
    alert("错题本为空：请先做题并提交，产生错题后再使用错题强化模式。");
    return;
  }

  const selectedDifficulty = (document.getElementById('selectedDifficulty')||{}).value || "All";
  const wrongKeys = new Set(errs.map(e => String(e.word||'').toLowerCase()).filter(Boolean));

  let pool = SAT_FULL_VOCAB.filter(v => wrongKeys.has(String(v.word||'').toLowerCase()));
  if (selectedDifficulty !== "All") pool = pool.filter(v => v.difficulty === selectedDifficulty);

  if (pool.length === 0) {
    alert("当前难度下没有可用错题。请切换难度到“全部难度”再试。");
    return;
  }

  const picked = __pickRandom__(pool, Math.min(count, pool.length));
  document.getElementById('loadingOverlay').style.display = 'flex';
  __buildBatchFromVocab__(picked);
  document.getElementById('loadingOverlay').style.display = 'none';
  // 注意：统计“已考词汇”只在提交后更新；这里不调用 updateStats()
}

function startSmartReviewMode(count = 10){
  if (!Array.isArray(SAT_FULL_VOCAB) || SAT_FULL_VOCAB.length === 0) {
    alert("词汇库未加载");
    return;
  }
  const selectedDifficulty = (document.getElementById('selectedDifficulty')||{}).value || "All";
  const errs = Array.isArray(errorRecords) ? errorRecords : [];
  const wrongKeys = new Set(errs.map(e => String(e.word||'').toLowerCase()).filter(Boolean));

  // 错题优先：默认 70% 错题 + 30% 新/未错词
  const wrongCount = Math.max(0, Math.min(count, Math.round(count * 0.7)));
  const newCount = Math.max(0, count - wrongCount);

  let wrongPool = SAT_FULL_VOCAB.filter(v => wrongKeys.has(String(v.word||'').toLowerCase()));
  let newPool = SAT_FULL_VOCAB.filter(v => !wrongKeys.has(String(v.word||'').toLowerCase()));

  // 更偏向“未考词”
  newPool = newPool.filter(v => !testedWords.has(String(v.word||'').toLowerCase()));

  if (selectedDifficulty !== "All") {
    wrongPool = wrongPool.filter(v => v.difficulty === selectedDifficulty);
    newPool = newPool.filter(v => v.difficulty === selectedDifficulty);
  }

  const pickedWrong = __pickRandom__(wrongPool, Math.min(wrongCount, wrongPool.length));
  const neededNew = count - pickedWrong.length;

  let pickedNew = __pickRandom__(newPool, Math.min(neededNew, newPool.length));

  // 若新词不足，则用“未错但已考”补齐
  if (pickedNew.length < neededNew) {
    let fallback = SAT_FULL_VOCAB.filter(v =>
      !wrongKeys.has(String(v.word||'').toLowerCase()) &&
      testedWords.has(String(v.word||'').toLowerCase())
    );
    if (selectedDifficulty !== "All") fallback = fallback.filter(v => v.difficulty === selectedDifficulty);
    const extra = __pickRandom__(fallback, neededNew - pickedNew.length);
    pickedNew = pickedNew.concat(extra);
  }

  // 若仍不足，则直接从错题池再补齐（保证总题数）
  let combined = pickedWrong.concat(pickedNew);
  if (combined.length < count) {
    const extraWrong = __pickRandom__(wrongPool.filter(v => !combined.some(x => String(x.word||'').toLowerCase() === String(v.word||'').toLowerCase())), count - combined.length);
    combined = combined.concat(extraWrong);
  }

  if (combined.length === 0) {
    alert("当前没有可复习的题目（可能词库为空或筛选条件过严）。");
    return;
  }

  // 最终洗牌
  combined = __pickRandom__(combined, combined.length);

  document.getElementById('loadingOverlay').style.display = 'flex';
  __buildBatchFromVocab__(combined.slice(0, count));
  document.getElementById('loadingOverlay').style.display = 'none';
  // 注意：统计“已考词汇”只在提交后更新；这里不调用 updateStats()
}

