// ===== Export All Vocab (Preview + XLS) =====

function __escapeHTML__(s){
  if (s === null || s === undefined) return '';
  return String(s)
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;')
    .replace(/'/g,'&#39;');
}

function openExportVocabModal(){
  const modal = document.getElementById('exportVocabModal');
  if (!modal) return;

  // fill letters once
  const letterSel = document.getElementById('exportLetterSelect');
  if (letterSel && letterSel.options.length <= 1) {
    const A = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('');
    A.forEach(ch=>{
      const opt = document.createElement('option');
      opt.value = ch;
      opt.textContent = ch;
      letterSel.appendChild(opt);
    });
  }

  modal.style.display = 'block';
  renderExportVocabPreview();
}

function closeExportVocabModal(){
  const modal = document.getElementById('exportVocabModal');
  if (modal) modal.style.display = 'none';
}

function _getAllVocabArray(){
  // SAT_FULL_VOCAB: 全量词库（全局变量）
  try { if (typeof SAT_FULL_VOCAB !== 'undefined' && Array.isArray(SAT_FULL_VOCAB)) return SAT_FULL_VOCAB; } catch(_) {}
  // 兼容其它命名
  try { if (Array.isArray(window.SAT_FULL_VOCAB)) return window.SAT_FULL_VOCAB; } catch(_) {}
  try { if (typeof vocabData !== 'undefined' && Array.isArray(vocabData)) return vocabData; } catch(_) {}
  try { if (Array.isArray(window.vocabData)) return window.vocabData; } catch(_) {}
  return [];
}

function _normalizeDifficulty(d){
  if (!d) return 'Medium';
  if (d === 'Basic' || d === 'Medium' || d === 'Hard') return d;
  const s = String(d).toLowerCase();
  if (s.includes('basic') || s.includes('easy')) return 'Basic';
  if (s.includes('hard')) return 'Hard';
  return 'Medium';
}

function _sortedVocab(arr){
  // 统一：单词大小写不区分（aviary 与 Aviary 视为同一个词）
  const raw = arr.map(x=>({
    word: (x.word||'').trim(),
    definition: x.definition||'',
    sentence: x.sentence||'',
    difficulty: _normalizeDifficulty(x.difficulty)
  })).filter(x=>x.word);

  // 去重（case-insensitive），保留信息更完整的一条
  const byKey = new Map();
  raw.forEach(v=>{
    const key = v.word.toLowerCase();
    const prev = byKey.get(key);
    if (!prev) { byKey.set(key, v); return; }

    // 选择“更完整”的记录：definition/sentence 更长优先；difficulty 不同则取更难的（Hard>Medium>Basic）
    const score = (o)=> (o.definition?o.definition.length:0) + (o.sentence?o.sentence.length:0);
    const dRank = {Basic:0, Medium:1, Hard:2};
    let keep = prev;
    if (score(v) > score(prev)) keep = v;
    else if (score(v) == score(prev)) {
      const a = dRank[v.difficulty] ?? 0;
      const b = dRank[prev.difficulty] ?? 0;
      if (a > b) keep = v;
    }
    byKey.set(key, keep);
  });

  const copy = Array.from(byKey.values());

  // sort: difficulty order, then first letter, then word
  const dOrder = {Basic:0, Medium:1, Hard:2};
  copy.sort((a,b)=>{
    const da = dOrder[a.difficulty] ?? 9;
    const db = dOrder[b.difficulty] ?? 9;
    if (da !== db) return da - db;
    const la = a.word[0].toUpperCase();
    const lb = b.word[0].toUpperCase();
    if (la !== lb) return la.localeCompare(lb);
    return a.word.toLowerCase().localeCompare(b.word.toLowerCase());
  });
  return copy;
}

function renderExportVocabPreview(){
  const all = _sortedVocab(_getAllVocabArray());
  const diffSel = document.getElementById('exportDifficultySelect');
  const letterSel = document.getElementById('exportLetterSelect');
  const preview = document.getElementById('exportVocabPreview');
  const summary = document.getElementById('exportVocabSummary');
  if (!preview) return;

  const diff = diffSel ? diffSel.value : 'ALL';
  const letter = letterSel ? letterSel.value : 'ALL';

  let filtered = all;
  if (diff !== 'ALL') filtered = filtered.filter(v => v.difficulty === diff);
  if (letter !== 'ALL') filtered = filtered.filter(v => (v.word[0]||'').toUpperCase() === letter);

  const total = all.length;
  const shown = Math.min(filtered.length, 200);

  if (summary) {
    summary.innerHTML = `总词汇量：<b>${total}</b>　｜　当前筛选：<b>${filtered.length}</b>　（预览显示前 ${shown} 条）`;
  }

  const rows = filtered.slice(0, 200).map((v, idx)=>`
    <tr>
      <td style="padding:8px;border-bottom:1px solid #e2e8f0;width:60px;">${idx+1}</td>
      <td style="padding:8px;border-bottom:1px solid #e2e8f0;width:140px;font-weight:700;">${__escapeHTML__(v.word)}</td>
      <td style="padding:8px;border-bottom:1px solid #e2e8f0;width:90px;">${v.difficulty}</td>
      <td style="padding:8px;border-bottom:1px solid #e2e8f0;">${__escapeHTML__(v.definition)}</td>
    </tr>
  `).join('');

  preview.innerHTML = `
    <table style="width:100%;border-collapse:collapse;">
      <thead>
        <tr>
          <th style="text-align:left;padding:8px;border-bottom:2px solid #cbd5e1;">#</th>
          <th style="text-align:left;padding:8px;border-bottom:2px solid #cbd5e1;">Word</th>
          <th style="text-align:left;padding:8px;border-bottom:2px solid #cbd5e1;">Level</th>
          <th style="text-align:left;padding:8px;border-bottom:2px solid #cbd5e1;">Definition</th>
        </tr>
      </thead>
      <tbody>${rows || `<tr><td colspan="4" style="padding:12px;color:#64748b;">无数据</td></tr>`}</tbody>
    </table>
  `;
}

function exportAllVocabToXls(){
  const all = _sortedVocab(_getAllVocabArray());
  if (!all.length) { alert('未找到词汇数据，无法导出。'); return; }

  // Group by difficulty then letter
  const groups = {Basic:[], Medium:[], Hard:[]};
  all.forEach(v=>{ (groups[v.difficulty] ||= []).push(v); });

  function tableFor(list){
    const rows = list.map(v=>`
      <tr>
        <td>${__escapeHTML__(v.word)}</td>
        <td>${__escapeHTML__(v.definition || '')}</td>
        <td>${__escapeHTML__(v.difficulty || '')}</td>
      </tr>`).join('');
    return `
      <table border="1" cellspacing="0" cellpadding="4">
        <tr><th>Word</th><th>Definition</th><th>Level</th></tr>
        ${rows}
      </table>
    `;
  }

  const content = `
    <html><head><meta charset="UTF-8"></head><body>
      <h2>SAT Vocabulary Export</h2>
      <p>Sorted by: Level → First letter → Word</p>
      <h3>Basic</h3>${tableFor(groups.Basic)}
      <br/><h3>Medium</h3>${tableFor(groups.Medium)}
      <br/><h3>Hard</h3>${tableFor(groups.Hard)}
    </body></html>
  `;

  const blob = new Blob([content], {type: 'application/vnd.ms-excel;charset=utf-8'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `SAT_Vocab_Export_${new Date().toISOString().slice(0,10)}.xls`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}



// ===== Auth gate hook =====
window.__startAfterAuth__ = function(){
  // Prevent double start
  if (window.__APP_STARTED__) return;
  window.__APP_STARTED__ = true;

  // Initialize vocab + stats
  try { loadVocab(); } catch(e){ console.error(e); }

  // If you want: you can also auto-render last screen/state here.
};

// If user is already authenticated (e.g. you modify code later), allow autostart.
document.addEventListener('DOMContentLoaded', function(){
  try{
    const statusEl = document.getElementById('vocabLoadStatus');
    if(statusEl && !window.__AUTH_OK__){
      statusEl.textContent = '请先登录后加载词库';
    }
    if(window.__AUTH_OK__){
      window.__startAfterAuth__();
    }
  }catch(e){ console.error(e); }
});
